export const BrainIcon: React.FC<BrainIconProps> = ({
  className,
  size = 24,
  color,
  logoUrl,
}) => {
  const uid = React.useId();
  const gradientId = `mbBrainGrad-${uid}`;

  if (logoUrl) {
    return (
      <img
        src={logoUrl}
        alt="Agent Logo"
        className={className}
        width={size}
        height={size}
        style={{ objectFit: "contain" }}
      />
    );
  }

  return (
    <svg
      width={size}
      height={size * 0.985}
      viewBox="0 0 27.71 27.3"
      className={className}
      fill={color || `url(#${gradientId})`}
    >
      <defs>
        <linearGradient id={gradientId} x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#00dc82" />
          <stop offset="100%" stopColor="#a78bfa" />
        </linearGradient>
      </defs>
      <path d={MB_LOGO_PATH} />
    </svg>
  );
};
